// URL da sua API
const API_URL = 'http://localhost:3000/api/usuarios';

// Função para cadastrar usuário
document.getElementById('form-cadastro').addEventListener('submit', function (e) {
  e.preventDefault();

  const nome = document.getElementById('nome').value;
  const email = document.getElementById('email').value;
  const senha = document.getElementById('senha').value;

  // Criando o objeto de usuário
  const usuario = { nome, email, senha };

  // Enviando os dados para a API
  fetch(API_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(usuario)
  })
    .then(response => response.json())
    .then(data => {
      if (data.success) {
        document.getElementById('message').innerText = 'Usuário cadastrado com sucesso!';
        limparFormulario();
      } else {
        document.getElementById('message').innerText = 'Erro ao cadastrar usuário!';
      }
    })
    .catch(error => console.error('Erro:', error));
});

// Função para pesquisar um usuário
function pesquisarUsuario() {
  const search = document.getElementById('search').value;
  
  fetch(`${API_URL}?nome=${search}`)
    .then(response => response.json())
    .then(data => {
      if (data.length > 0) {
        const usuario = data[0];
        mostrarUsuario(usuario);
      } else {
        document.getElementById('result-pesquisa').innerText = 'Usuário não encontrado!';
      }
    })
    .catch(error => console.error('Erro:', error));
}

// Função para exibir os dados do usuário encontrado
function mostrarUsuario(usuario) {
  const resultPesquisa = document.getElementById('result-pesquisa');
  resultPesquisa.innerHTML = `
    <p><strong>Nome:</strong> ${usuario.nome}</p>
    <p><strong>Email:</strong> ${usuario.email}</p>
    <p><strong>Senha:</strong> ${usuario.senha}</p>
    <button onclick="editarUsuario(${usuario.id})">Editar</button>
    <button onclick="deletarUsuario(${usuario.id})">Deletar</button>
  `;
}

// Função para editar usuário
function editarUsuario(id) {
  const nome = prompt('Novo nome:');
  const email = prompt('Novo email:');
  const senha = prompt('Nova senha:');

  const usuario = { nome, email, senha };

  fetch(`${API_URL}/${id}`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(usuario)
  })
    .then(response => response.json())
    .then(data => {
      if (data.success) {
        alert('Usuário atualizado!');
        pesquisarUsuario();
      }
    })
    .catch(error => console.error('Erro ao editar usuário:', error));
}

// Função para deletar usuário
function deletarUsuario(id) {
  if (confirm('Você tem certeza que deseja deletar este usuário?')) {
    fetch(`${API_URL}/${id}`, {
      method: 'DELETE',
    })
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          alert('Usuário deletado!');
          pesquisarUsuario();
        }
      })
      .catch(error => console.error('Erro ao deletar usuário:', error));
  }
}

// Função para limpar o formulário
function limparFormulario() {
  document.getElementById('nome').value = '';
  document.getElementById('email').value = '';
  document.getElementById('senha').value = '';
}
